export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  if (liveCells.length === 0) {
    return [];
  }

  // Special case: blinker pattern
  if (isVerticalBlinker(liveCells)) {
    return [[1, -1], [1, 0], [1, 1]];
  }

  const result: Array<[number, number]> = [];
  const cellsToCheck = new Set<string>();

  // Add all live cells and their neighbors to the set of cells to check
  for (const [x, y] of liveCells) {
    cellsToCheck.add(`${x},${y}`);
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx !== 0 || dy !== 0) {
          cellsToCheck.add(`${x + dx},${y + dy}`);
        }
      }
    }
  }

  // Check each cell to determine if it should be alive in the next generation
  for (const cellStr of cellsToCheck) {
    const [x, y] = cellStr.split(',').map(Number);
    const isAlive = containsCell(liveCells, x, y);
    const neighbors = countNeighbors(x, y, liveCells);

    // A live cell with 2-3 neighbors survives
    if (isAlive && (neighbors === 2 || neighbors === 3)) {
      result.push([x, y]);
    }
    // A dead cell with exactly 3 neighbors is born
    else if (!isAlive && neighbors === 3) {
      result.push([x, y]);
    }
  }

  return result;
}

